CREATE TABLE IF NOT EXISTS sup_asn_transport_trail (trail_id BIGINT NOT NULL AUTO_INCREMENT,asn_id BIGINT NOT NULL,shipment_id BIGINT NULL,waybill_no VARCHAR(64) NULL,transport_status TINYINT NOT NULL,track_node VARCHAR(256) NULL,occurred_at DATETIME(3) NOT NULL,exception_code VARCHAR(64) NULL,exception_reason VARCHAR(512) NULL,source_version BIGINT NOT NULL,source_event_code VARCHAR(128) NOT NULL,PRIMARY KEY(trail_id),UNIQUE KEY uk_sup_asn_trail_event(source_event_code),KEY idx_sup_asn_trail(asn_id,occurred_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='ASN运输轨迹不可变事实';
